
#include "svg_helper.h"
int main(){string stem="06_selection_sort",title="06 Selection Sort"; vector<vector<int>> frames={{5,3,8,1,4,7},{5,3,8,1,4,7},{5,3,8,1,4,7},{1,3,8,5,4,7},{1,3,8,5,4,7},{1,3,8,5,4,7},{1,3,4,5,8,7},{1,3,4,5,7,8}}; vector<int> scan={1,2,3,0,3,4,2,5}; vector<int> minidx={1,1,3,0,1,1,4,5}; vector<string> f={"scan unsorted suffix","track minimum index","swap minimum to front","sorted prefix grows"}; for(int k=0;k<frames.size();++k){int W=1140,H=680; set<int> hot={scan[k]}, done; int prefix=(k>=3?1:0)+(k>=6?2:0)+(k>=7?3:0); for(int i=0;i<prefix;i++) done.insert(i); set<int> piv={minidx[k]}; string s=startSVG(W,H,title,"Step "+to_string(k+1)+" / "+to_string(frames.size())+" - scan to select minimum"); s+=box(50,120,610,400,"#fff","#bfd3e6"); s+=T(90,155,"Selection sort: keep min while scanning unsorted region",17,"#123","700"); s+=arr(frames[k],90,190,hot,done,piv); s+=T(90+minidx[k]*58,175,"min",15,"#d97706","700"); s+=T(90+scan[k]*58,282,"scan",15,"#dc2626","700"); s+=arrow(90+scan[k]*58+29,270,90+minidx[k]*58+29,270,"#f59e0b",4); s+=box(90,335,410,95,"#f8fafc","#94a3b8"); s+=T(110,365,"Sorted prefix",16,"#166534","700"); s+=T(250,365,"|",20); s+=T(285,365,"Unsorted suffix being scanned",16,"#1e3a8a","700"); s+=bars(frames[k],100,540,hot,done,piv); s+=sidebar(k+1,frames.size(),f)+footer(W,H,stem+".cpp"); stringstream p; p<<"output/"<<stem<<"_steps/step_"<<setw(2)<<setfill('0')<<k+1<<".svg"; writeFile(p.str(),s+endSVG());}}
